const GROUP_MAP = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly' },
  '120363420996892188@g.us': { context: 'garlic',   label: 'Garlic N Lemon' },
  '120363422948599063@g.us': { context: 'ernesto',  label: 'Ernesto' },
};

const raw  = $input.first().json;
const body = raw.body || raw;

const debugKeys = Object.keys(body || {}).join(', ');
const debugData = body?.data ? Object.keys(body.data).join(', ') : 'n/a';

const messageText =
  body?.text ||
  body?.message?.text ||
  body?.message?.body ||
  body?.data?.text ||
  body?.data?.message?.text ||
  body?.data?.message?.body ||
  body?.data?.message?.conversation ||
  body?.data?.message?.extendedTextMessage?.text ||
  '';

const senderName =
  body?.senderName ||
  body?.message?.senderName ||
  body?.data?.senderName ||
  body?.sender?.pushname ||
  body?.data?.pushName ||
  'Unknown';

const chatId =
  body?.chatid ||
  body?.chatId ||
  body?.wa_chatid ||
  body?.waChatId ||
  body?.remoteJid ||
  body?.data?.key?.remoteJid ||
  body?.data?.message?.key?.remoteJid ||
  body?.message?.key?.remoteJid ||
  body?.id ||
  body?.data?.chatid ||
  body?.data?.chatId ||
  body?.data?.wa_chatid ||
  body?.data?.remoteJid ||
  body?.message?.chatid ||
  body?.message?.chatId ||
  body?.message?.remoteJid ||
  '';

const groupInfo = GROUP_MAP[chatId] || { context: 'unknown', label: 'Unknown' };
const cleanMessage = String(messageText || '')
  .replace(/@jarvis/ig, '')
  .replace(/59739253801103/g, '')
  .replace(/@\w+/g, '')
  .trim();

return [{ json: {
  rawMessage: messageText,
  cleanMessage,
  senderName,
  chatId,
  waChatId: chatId,
  groupContext: groupInfo.context,
  groupLabel: groupInfo.label,
  timestamp: new Date().toISOString(),
  _debug_keys: debugKeys,
  _debug_data_keys: debugData
}}];

const inputData = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.groupMemory = staticData.groupMemory || {};

let responseText = '';
if (inputData?.message?.content) responseText = inputData.message.content;
else if (inputData?.choices?.[0]?.message?.content) responseText = inputData.choices[0].message.content;
else if (typeof inputData?.text === 'string') responseText = inputData.text;
else responseText = JSON.stringify(inputData);

let parsed;
try {
  const clean = responseText.replace(/\u0060\u0060\u0060json/g, '').replace(/\u0060\u0060\u0060/g, '').trim();
  const match = clean.match(/({[\s\S]*})/);
  parsed = JSON.parse(match ? match[1] : clean);
} catch (e) {
  parsed = { intent: 'none', reply: 'Não consegui processar. Pode reformular?', entity: {} };
}

const pm = $('Check Personality Command').first().json;
const ctx = $('Build Context').first().json;
const chatId = pm.chatId || pm.waChatId || 'unknown';

let knownProjects = [];
try { knownProjects = JSON.parse(ctx.projectsList || '[]'); } catch (e) { knownProjects = []; }

if (!staticData.groupMemory[chatId]) {
  staticData.groupMemory[chatId] = {
    messages: [],
    lastProjectId: null,
    lastProjectName: '',
    pendingTask: null,
    pendingTicket: null,
  };
}
const chatMemory = staticData.groupMemory[chatId];

const normalize = (v) => String(v || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const mapIntent = (rawIntent, msg) => {
  const i = normalize(rawIntent).replace(/\s+/g, '_');
  if (['create_task','task','criar_tarefa','tarefa'].includes(i)) return 'create_task';
  if (['create_ticket','ticket','criar_ticket','chamado'].includes(i)) return 'create_ticket';
  if (['create_project','project','criar_projeto','projeto_novo'].includes(i)) return 'create_project';
  if (['create_payment_incoming','payment_incoming','incoming'].includes(i)) return 'create_payment_incoming';
  if (['create_payment_outgoing','payment_outgoing','outgoing'].includes(i)) return 'create_payment_outgoing';

  const m = normalize(msg);
  const isTicket = /(bug|erro|quebrou|falha|nao funciona|não funciona|ticket|chamado|problema)/.test(m);
  const isTask = /(task|tarefa|fazer|criar|implementar|ajustar|melhorar|alterar)/.test(m);
  if (isTicket) return 'create_ticket';
  if (isTask) return 'create_task';
  return 'none';
};

const overlapScore = (a, b) => {
  const aa = normalize(a).split(' ').filter(x => x.length > 2);
  const bb = normalize(b).split(' ').filter(x => x.length > 2);
  if (aa.length === 0 || bb.length === 0) return 0;
  const setB = new Set(bb);
  const hits = aa.filter(x => setB.has(x)).length;
  return hits / Math.max(aa.length, bb.length);
};

const findProjectByName = (name, pool = knownProjects) => {
  const target = normalize(name);
  if (!target || !pool.length) return null;

  let direct = pool.find(p => normalize(p.name) === target);
  if (direct) return direct;

  direct = pool.find(p => {
    const pn = normalize(p.name);
    return pn.includes(target) || target.includes(pn);
  });
  if (direct) return direct;

  let best = null;
  let bestScore = 0;
  for (const p of pool) {
    const s = overlapScore(target, p.name);
    if (s > bestScore) {
      bestScore = s;
      best = p;
    }
  }
  return bestScore >= 0.34 ? best : null;
};

const inferProjectFromMessage = (message, pool = knownProjects) => {
  const msg = normalize(message);
  if (!msg || !pool.length) return null;
  const hits = pool.filter(p => {
    const pn = normalize(p.name);
    return pn && (msg.includes(pn) || pn.split(' ').some(w => w.length > 3 && msg.includes(w)));
  });
  return hits.length === 1 ? hits[0] : null;
};

const entity = parsed.entity || {};
const currentMessage = pm.cleanMessage || pm.rawMessage || '';
const replyTarget = pm.waChatId || pm.chatId || '120363426390515923@g.us';
let finalIntent = mapIntent(parsed.intent || 'none', currentMessage);

const groupClient = pm.groupContext === 'garlic' ? 'garlic' : (pm.groupContext === 'ernesto' ? 'ernesto' : '');
const groupProjects = groupClient
  ? knownProjects.filter(p => normalize(p.client_name).includes(groupClient) || normalize(p.name).includes(groupClient))
  : [];

const resolveProject = () => {
  if (!knownProjects.length) return null;

  if (entity.project_name) {
    const byNameInGroup = groupProjects.length ? findProjectByName(entity.project_name, groupProjects) : null;
    if (byNameInGroup) return byNameInGroup;

    const byNameGlobal = findProjectByName(entity.project_name, knownProjects);
    if (byNameGlobal) return byNameGlobal;
  }

  if (entity.project_id) {
    const byId = knownProjects.find(p => String(p.id) === String(entity.project_id));
    if (byId) return byId;
  }

  const byMsgInGroup = groupProjects.length ? inferProjectFromMessage(currentMessage, groupProjects) : null;
  if (byMsgInGroup) return byMsgInGroup;

  const byMsgGlobal = inferProjectFromMessage(currentMessage, knownProjects);
  if (byMsgGlobal) return byMsgGlobal;

  if (groupProjects.length === 1) return groupProjects[0];

  if (ctx.defaultProjectId) {
    const byCtx = knownProjects.find(p => String(p.id) === String(ctx.defaultProjectId));
    if (byCtx) return byCtx;
  }

  if (chatMemory.lastProjectId) {
    const byMem = knownProjects.find(p => String(p.id) === String(chatMemory.lastProjectId));
    if (byMem) return byMem;
  }

  return null;
};

const retryHint = /(^|\s)(consegue|agora|agora sim|pode|vai|segue|manda ver|tenta de novo|retry|sim)(\s|$)/i.test(currentMessage);
if (finalIntent === 'none' && (chatMemory.pendingTask || chatMemory.pendingTicket) && retryHint) {
  if (chatMemory.pendingTask) {
    finalIntent = 'create_task';
    Object.assign(entity, chatMemory.pendingTask);
  } else if (chatMemory.pendingTicket) {
    finalIntent = 'create_ticket';
    Object.assign(entity, chatMemory.pendingTicket);
  }
}

let resolvedProject = null;

if (finalIntent === 'create_task') {
  if (!entity.title) {
    finalIntent = 'none';
    parsed.reply = 'Preciso do título da tarefa. Pode detalhar mais?';
  } else {
    resolvedProject = resolveProject();
    if (resolvedProject) {
      entity.project_id = resolvedProject.id;
      entity.project_name = resolvedProject.name;
      chatMemory.lastProjectId = resolvedProject.id;
      chatMemory.lastProjectName = resolvedProject.name;
      chatMemory.pendingTask = null;
    } else {
      chatMemory.pendingTask = {
        title: entity.title || '',
        description: entity.description || '',
        priority: entity.priority || 'medium',
        project_name: entity.project_name || '',
      };
      finalIntent = 'none';
      parsed.reply = knownProjects.length > 0
        ? '⚠️ Não consegui identificar o projeto da task. Me diga o projeto exato ou confirme que uso o projeto padrão do grupo.'
        : '⚠️ Não consegui carregar projetos do Cockpit agora. Tenta novamente em instantes.';
    }
  }
}

if (finalIntent === 'create_ticket') {
  if (!entity.subject && !entity.title) {
    finalIntent = 'none';
    parsed.reply = 'Preciso do assunto do ticket. Pode descrever o problema?';
  } else {
    resolvedProject = resolveProject();
    if (resolvedProject) {
      entity.project_id = resolvedProject.id;
      entity.project_name = resolvedProject.name;
      chatMemory.lastProjectId = resolvedProject.id;
      chatMemory.lastProjectName = resolvedProject.name;
    }
    chatMemory.pendingTicket = {
      subject: entity.subject || entity.title || '',
      description: entity.description || '',
      priority: entity.priority || 'medium',
      category: entity.category || 'question',
    };
    chatMemory.pendingTask = null;
  }
}

if (finalIntent !== 'create_ticket') chatMemory.pendingTicket = null;

const clientName = entity.client_name ||
  (pm.groupContext === 'garlic' ? 'Garlic N Lemon' :
   pm.groupContext === 'ernesto' ? 'Ernesto Pizza' : 'Angel Fly');

if (finalIntent !== 'none') {
  parsed.reply = 'Processando sua solicitação...';
}

return [{ json: {
  intent: finalIntent,
  entity,
  title: entity.title || entity.subject || '',
  description: entity.description || '',
  priority: entity.priority || 'medium',
  project_id: entity.project_id || null,
  project_name: entity.project_name || '',
  subject: entity.subject || entity.title || '',
  category: entity.category || 'question',
  client_name: clientName,
  amount: entity.amount || 0,
  reply: parsed.reply || 'Entendido!',
  senderName: pm.senderName,
  chatId: pm.chatId,
  waChatId: replyTarget,
  groupContext: pm.groupContext,
  groupLabel: pm.groupLabel
}}];

const msg = $input.first().json.cleanMessage.toLowerCase();

// Detect personality adjustment commands
const isPersonalityCmd = (
  (msg.includes('humor') || msg.includes('seriedade') || msg.includes('sério') || msg.includes('serio') || msg.includes('personalidade'))
  && (msg.includes('aument') || msg.includes('diminui') || msg.includes('reduz') || msg.includes('coloca') || msg.includes('%') || /\d+/.test(msg))
);

return [{ json: { ...($input.first().json), isPersonalityCmd } }];

const staticData = $getWorkflowStaticData('global');
const msg = $input.first().json.cleanMessage.toLowerCase();

// Current level (0 = serious, 100 = very funny)
let currentLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;

// Extract percentage from message
const pctMatch = msg.match(/(\d+)\s*%/);
const numMatch = msg.match(/(\d+)/);
const pct = pctMatch ? parseInt(pctMatch[1]) : (numMatch ? parseInt(numMatch[1]) : 20);

let newLevel = currentLevel;
let action = '';

if (msg.includes('aument') || msg.includes('mais')) {
  newLevel = Math.min(100, currentLevel + pct);
  action = 'aumentado';
} else if (msg.includes('diminui') || msg.includes('reduz') || msg.includes('menos')) {
  newLevel = Math.max(0, currentLevel - pct);
  action = 'reduzido';
} else if (msg.includes('coloca') || msg.includes('define') || msg.includes('set')) {
  newLevel = Math.min(100, Math.max(0, pct));
  action = 'definido para';
}

staticData.humorLevel = newLevel;

const levelDesc = newLevel <= 20 ? 'muito sério' : newLevel <= 40 ? 'sério' : newLevel <= 60 ? 'equilibrado' : newLevel <= 80 ? 'descontraído' : 'bem humorado';

return [{ json: {
  waChatId: $input.first().json.waChatId,
  reply: `✅ Nível de humor ${action}: ${newLevel}% (${levelDesc}). Ajuste aplicado.`
}}];

const staticData = $getWorkflowStaticData('global');
staticData.groupMemory = staticData.groupMemory || {};

const humorLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;
const pm = $('Check Personality Command').first().json;
const chatId = pm.chatId || pm.waChatId || 'unknown';

if (!staticData.groupMemory[chatId]) {
  staticData.groupMemory[chatId] = {
    messages: [],
    lastProjectId: null,
    lastProjectName: '',
    pendingTask: null,
    pendingTicket: null,
  };
}
const chatMemory = staticData.groupMemory[chatId];

const GROUP_KNOWLEDGE = {
  garlic: {
    default_client: "Garlic'n Lemons",
    canonical_project: "Garlic'n Lemons SaaS",
    aliases: ["gnl", "garlic", "garlic n lemons", "garlic'n lemons", "gnl system", "gnl-backend", "gnl-pickup", "gnl-catering"],
    systems: ["backend", "website", "pickup", "catering"],
    intent_hint: "Neste grupo, task/ticket normalmente é do projeto Garlic'n Lemons."
  },
  ernesto: {
    default_client: "Ernesto's Pizza",
    canonical_project: "Ernestos Pizza System",
    aliases: ["ernestos", "ernesto's pizza", "north end", "somerville", "fax bridge"],
    systems: ["backend", "website", "pickup", "catering"],
    intent_hint: "Neste grupo, task/ticket normalmente é do projeto Ernesto's Pizza."
  },
  angelfly: {
    default_client: "Angel Fly",
    canonical_project: "Angel Fly Cockpit",
    aliases: ["cockpit", "jarvis", "angelfly"],
    systems: ["cockpit", "n8n", "automation"],
    intent_hint: "Neste grupo, pedidos geralmente são internos/operacionais da Angel Fly."
  }
};

const extractMessages = (raw) => {
  if (!raw) return [];
  return Array.isArray(raw) ? raw :
    Array.isArray(raw?.messages) ? raw.messages :
    Array.isArray(raw?.data?.messages) ? raw.data.messages :
    Array.isArray(raw?.data?.data?.messages) ? raw.data.data.messages :
    Array.isArray(raw?.data) ? raw.data :
    Array.isArray(raw?.result?.messages) ? raw.result.messages :
    [];
};

const extractText = (m) => (
  m?.text || m?.body || m?.messageText ||
  m?.content?.conversation || m?.content?.extendedTextMessage?.text ||
  m?.message?.conversation || m?.message?.extendedTextMessage?.text || ''
).trim();

let historyText = '';
try {
  const historyData = $('Debug History').first().json;
  let msgs = historyData?._extractedMessages || [];

  if (msgs.length === 0) {
    const raw = $('Get Chat History').first().json;
    msgs = extractMessages(raw);
  }

  const inboundText = (pm.cleanMessage || pm.rawMessage || '').trim();
  if (inboundText) {
    const last = chatMemory.messages?.[chatMemory.messages.length - 1];
    if (!last || last.text !== inboundText) {
      chatMemory.messages.push({
        senderName: pm.senderName || 'Membro',
        text: inboundText,
        fromMe: false,
        ts: Date.now(),
      });
    }
  }

  if (Array.isArray(chatMemory.messages) && chatMemory.messages.length > 150) {
    chatMemory.messages = chatMemory.messages.slice(-150);
  }

  const memoryMsgs = Array.isArray(chatMemory.messages) ? chatMemory.messages : [];
  const combined = [...msgs, ...memoryMsgs];

  const lines = combined
    .map(m => ({
      name: m.fromMe ? 'ANGELFLY (Jarvis)' : (m.senderName || m.pushName || m.name || 'Membro'),
      txt: extractText(m),
    }))
    .filter(x => x.txt && x.txt.length > 0)
    .slice(-100)
    .map(x => '[' + x.name + ']: ' + x.txt);

  historyText = lines.length > 0
    ? lines.join('\n')
    : '(histórico não disponível - responda com base na mensagem atual)';
} catch (e) {
  historyText = '(erro ao carregar histórico)';
}

let projectsList = [];
let projectsRef = '  (nenhum projeto cadastrado)';
try {
  const fetchItems = $('Fetch Projects').all();
  const directRows = fetchItems.map(i => i.json).filter(Boolean);

  let wrappedRows = [];
  for (const row of directRows) {
    if (Array.isArray(row)) wrappedRows.push(...row);
    else if (Array.isArray(row?.data)) wrappedRows.push(...row.data);
    else if (Array.isArray(row?.projects)) wrappedRows.push(...row.projects);
    else if (Array.isArray(row?.items)) wrappedRows.push(...row.items);
  }

  const projs = wrappedRows.length > 0 ? wrappedRows : directRows;

  const seen = new Set();
  projectsList = projs
    .filter(p => p && p.id !== undefined && p.name)
    .filter(p => {
      const k = String(p.id);
      if (seen.has(k)) return false;
      seen.add(k);
      return true;
    })
    .filter(p => !p.status || ['active', 'assigned', 'in_progress', 'open'].includes(String(p.status).toLowerCase()))
    .map(p => ({ id: p.id, name: p.name, client_name: p.client_name || '' }));

  if (projectsList.length > 0) {
    projectsRef = projectsList
      .map(p => '  - id=' + p.id + ' | "' + p.name + '" | cliente: "' + p.client_name + '"')
      .join('\n');
  }
} catch (e) {
  projectsList = [];
}

let defaultProjectId = null;
let defaultProjectName = '';
if (chatMemory.lastProjectId) {
  const memProject = projectsList.find(p => String(p.id) === String(chatMemory.lastProjectId));
  if (memProject) {
    defaultProjectId = memProject.id;
    defaultProjectName = memProject.name;
  }
}

const groupKnowledge = GROUP_KNOWLEDGE[pm.groupContext] || null;
const groupKnowledgeSnippet = groupKnowledge
  ? [
      'Projeto canônico: ' + groupKnowledge.canonical_project,
      'Cliente padrão: ' + groupKnowledge.default_client,
      'Aliases: ' + groupKnowledge.aliases.join(', '),
      'Sistemas: ' + groupKnowledge.systems.join(', '),
      'Regra: ' + groupKnowledge.intent_hint
    ].join('\n')
  : 'Sem knowledge card específico para este grupo.';

const humorDesc = humorLevel <= 20 ? 'muito sério e formal, sem humor'
  : humorLevel <= 40 ? 'profissional com leveza ocasional'
  : humorLevel <= 60 ? 'equilibrado entre profissional e descontraído'
  : humorLevel <= 80 ? 'descontraído com bom humor moderado'
  : 'bem humorado e leve, com humor frequente';

return [{ json: {
  ...pm,
  humorLevel,
  humorDesc,
  projectsRef,
  projectsList: JSON.stringify(projectsList),
  historyText,
  defaultProjectId,
  defaultProjectName,
  cleanMessage: pm.cleanMessage || pm.rawMessage || '',
  groupKnowledgeSnippet,
} }];

// Debug: inspect raw Get Chat History response
const raw = $input.first().json;
console.log('RAW HISTORY KEYS:', Object.keys(raw || {}));
console.log('RAW HISTORY:', JSON.stringify(raw).slice(0, 500));

// Try all known Uzapi response shapes
const msgs =
  Array.isArray(raw) ? raw :
  Array.isArray(raw?.messages) ? raw.messages :
  Array.isArray(raw?.data?.messages) ? raw.data.messages :
  Array.isArray(raw?.data) ? raw.data :
  [];

console.log('MESSAGES FOUND:', msgs.length);
if (msgs.length > 0) console.log('FIRST MSG KEYS:', Object.keys(msgs[0]));

// Pass through original data + extracted messages
return [{ json: { ...raw, _extractedMessages: msgs, _msgCount: msgs.length } }];
